import React, { useState } from 'react';
import { Link, useNavigate } from "react-router-dom";
import '../styles/Navbar.css';

const Navbar = () => {
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const navigate = useNavigate();
    const isAuthenticated = localStorage.getItem('userToken');

    const toggleMenu = () => setIsMenuOpen(!isMenuOpen);

    return (
        <nav className="navbar">
            <div className="nav-left-section">
                {/* 1. The Hamburger */}
                <div className={`hamburger ${isMenuOpen ? 'active' : ''}`} onClick={toggleMenu}>
                    <span className="bar"></span>
                    <span className="bar"></span>
                    <span className="bar"></span>
                </div>

                <div className="nav-logo">
                    <Link to="/">PAU Connect</Link>
                </div>
            </div>

            {/* 2. The Menu Container */}
            <ul className={`nav-links ${isMenuOpen ? 'open' : ''}`}>
                <li><Link to="/" onClick={() => setIsMenuOpen(false)}>Home</Link></li>
                {isAuthenticated ? (
                    <>
                        <li><Link to="/Profile" onClick={() => setIsMenuOpen(false)}>Profile</Link></li>
                        <li><button onClick={() => { localStorage.removeItem('userToken'); navigate('/'); setIsMenuOpen(false); }}>Logout</button></li>
                    </>
                ) : (
                    <>
                        <li><Link to="/Login" onClick={() => setIsMenuOpen(false)}>Login</Link></li>
                        <li><button onClick={() => { navigate('/Register'); setIsMenuOpen(false); }}>Register</button></li>
                    </>
                )}
            </ul>
        </nav>
    );
};

export default Navbar;
